const form = $input.first().json;
const gaya = form['Gaya Bahasa'];
const botId = form['Bot ID'] || null;

const strategyMap = {
  engagement: ['warm_welcome','quick_assist','question_led','reassuring'],
  discovery: ['overview_first','benefit_first','clarifying_question','process_explainer'],
  evaluation: ['value_reframe','risk_reversal','social_proof','comparison_reframe','objection_handling'],
  conversion: ['soft_cta','next_step_guidance','friction_reduction','confirmation_reassurance'],
  retention: ['empathy_first','apology_solution','process_clarity','reassurance_followup']
};

const intents = [
  { category: 'engagement', intent: 'engagement.greeting_new', count: 3, desc: 'Sapaan hangat untuk kontak BARU yang pertama kali mengirim pesan. Bangun kesan pertama positif dan ajak pelanggan menyampaikan kebutuhannya.' },
  { category: 'engagement', intent: 'engagement.greeting_return', count: 3, desc: 'Sapaan untuk pelanggan LAMA yang kembali chat setelah lama tidak aktif (>24 jam). Tunjukkan bahwa kita ingat dan senang mereka kembali.' },
  { category: 'engagement', intent: 'engagement.time_inquiry', count: 3, desc: 'Menjawab pertanyaan tentang jam operasional, ketersediaan slot, atau kapan bisa konsultasi.' },
  { category: 'discovery', intent: 'discovery.program_detail', count: 4, desc: 'Menjelaskan gambaran umum program/jasa yang ditawarkan. Fokus pada overview, bukan detail teknis.' },
  { category: 'discovery', intent: 'discovery.schedule_location', count: 3, desc: 'Memberikan informasi jadwal, lokasi fisik, atau cara akses layanan (online/offline).' },
  { category: 'discovery', intent: 'discovery.tutor_profile', count: 3, desc: 'Menjawab pertanyaan tentang tim/tenaga ahli/pengajar. Fokus pada kredibilitas dan pengalaman.' },
  { category: 'discovery', intent: 'discovery.curriculum', count: 3, desc: 'Menjelaskan kurikulum, materi, metode kerja, atau tahapan layanan yang diberikan.' },
  { category: 'evaluation', intent: 'evaluation.pricing_inquiry', count: 4, desc: 'Menyampaikan informasi harga/biaya/paket secara informatif. Belum ada keberatan, murni tanya harga.' },
  { category: 'evaluation', intent: 'evaluation.objection_price', count: 4, desc: 'Menangani keberatan HARGA MAHAL. Fokus pada value & benefit.' },
  { category: 'evaluation', intent: 'evaluation.objection_compare', count: 3, desc: 'Menangani perbandingan langsung dengan kompetitor. Fokus pada diferensiasi tanpa menjatuhkan.' },
  { category: 'evaluation', intent: 'evaluation.objection_risk', count: 4, desc: 'Menangani ketakutan resiko. Fokus pada risk reversal.' },
  { category: 'evaluation', intent: 'evaluation.objection_authority', count: 3, desc: 'Menangani keraguan kredibilitas. Fokus pada social proof.' },
  { category: 'evaluation', intent: 'evaluation.objection_urgency', count: 3, desc: 'Menjawab pelanggan yang menunda keputusan, dorong tanpa terlalu menekan.' },
  { category: 'conversion', intent: 'conversion.soft', count: 3, desc: 'Ajakan lembut untuk pelanggan yang sudah tertarik tapi belum memutuskan.' },
  { category: 'conversion', intent: 'conversion.transaction', count: 3, desc: 'Instruksi pendaftaran/pembayaran yang jelas dan mudah diikuti.' },
  { category: 'conversion', intent: 'conversion.confirm', count: 3, desc: 'Konfirmasi penerimaan pendaftaran/pembayaran dan next step.' },
  { category: 'retention', intent: 'retention.complaint_service', count: 4, desc: 'Respons keluhan layanan dengan empati tinggi dan solusi konkret.' },
  { category: 'retention', intent: 'retention.complaint_refund', count: 3, desc: 'Menangani permintaan refund dengan empati dan proses jelas.' },
  { category: 'retention', intent: 'retention.progress_inquiry', count: 3, desc: 'Menjawab pertanyaan progres layanan yang sedang berjalan.' },
  { category: 'retention', intent: 'retention.reschedule', count: 3, desc: 'Membantu pelanggan mengubah jadwal atau reschedule sesi.' }
];

return intents.map(i => ({
  json: {
    ...i,
    gaya,
    botId,
    target_count: i.count,
    generation_count: i.count + 2,
    strategy_pool: strategyMap[i.category] || ['general_response']
  }
}));

const src = $input.first().json || {};
const promptData = $('Build Agnostic Prompt').first().json;
const raw = String(src.text || (src.response && src.response.text) || src.output || '');
let cleaned = raw.trim();
const bt = String.fromCharCode(96);
cleaned = cleaned.split(bt + bt + bt + 'json').join('');
cleaned = cleaned.split(bt + bt + bt).join('');

const firstBracket = cleaned.indexOf('[');
const lastBracket = cleaned.lastIndexOf(']');
if (firstBracket !== -1 && lastBracket !== -1 && lastBracket > firstBracket) {
  cleaned = cleaned.slice(firstBracket, lastBracket + 1);
}

const normalizeBool = (v) => {
  if (typeof v === 'boolean') return v;
  if (typeof v === 'string') return ['true', 'yes', '1'].includes(v.trim().toLowerCase());
  return false;
};

let templates = [];
let parseOk = false;
let parseError = null;
try {
  const parsed = JSON.parse(cleaned);
  if (!Array.isArray(parsed)) throw new Error('Output is not a JSON array');
  templates = parsed.map((t, idx) => ({
    name: String((t && (t.name || t.title || t.strategy)) || ('Template ' + (idx + 1))).trim(),
    strategy_tag: String((t && (t.strategy_tag || t.strategy)) || '').trim(),
    content: String((t && (t.content || t.template || t.text || t.message)) || '').trim(),
    category: promptData.category,
    sub_category: promptData.intent,
    requires_rag: normalizeBool(t && t.requires_rag) || /\[RAG:/i.test(String((t && (t.content || t.template || t.text || t.message)) || ''))
  }));
  parseOk = true;
} catch (e) {
  parseError = e.message;
}

return [{
  json: {
    intent: promptData.intent,
    category: promptData.category,
    targetCount: promptData.targetCount,
    generationCount: promptData.generationCount,
    strategyPool: promptData.strategyPool || [],
    raw_output: raw,
    parse_ok: parseOk,
    parse_error: parseError,
    parsed_count: templates.length,
    templates
  }
}];

const input = $input.first().json || {};
const intent = input.intent;
const category = input.category;
const targetCount = input.targetCount || 3;
const strategyPool = Array.isArray(input.strategyPool) ? input.strategyPool : [];
const sourceTemplates = Array.isArray(input.templates) ? input.templates : [];

const allowedPlaceholders = new Set(['nama_pelanggan','nama_bisnis','nama_jasa','nama_paket','harga','link_daftar','jam_operasional','lokasi','kontak_admin']);

const normalizeText = (s) => String(s || '')
  .toLowerCase()
  .replace(/\[rag:[^\]]+\]/gi, '[rag]')
  .replace(/\{[^}]+\}/g, '{var}')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const extractPlaceholders = (s) => {
  const out = [];
  const re = /\{([^{}]+)\}/g;
  let m;
  while ((m = re.exec(String(s || ''))) !== null) out.push(m[1].trim());
  return out;
};

const looksCustomerPerspective = (text) => {
  const t = String(text || '').toLowerCase();
  const bad = ['saya mau tanya','saya ingin tanya','aku mau tanya','saya tertarik','saya mau daftar','saya ingin daftar'];
  return bad.some(p => t.includes(p));
};

const hasSpecificPriceOrContact = (text) => {
  const t = String(text || '');
  return /(rp\s?\d|idr\s?\d|\$\s?\d|\b08\d{8,}\b|\b\d{4,}\b)/i.test(t);
};

let kept = [];
let rejected = [];
const seenContent = new Set();
const seenStrategy = new Set();

for (let i = 0; i < sourceTemplates.length; i++) {
  const t = sourceTemplates[i] || {};
  const item = {
    name: String(t.name || ('Template ' + (i + 1))).trim(),
    strategy_tag: String(t.strategy_tag || '').trim(),
    content: String(t.content || '').trim(),
    category,
    sub_category: intent,
    requires_rag: !!t.requires_rag || /\[RAG:/i.test(String(t.content || ''))
  };

  const issues = [];
  if (!item.content || item.content.length < 20) issues.push('content_too_short');
  if (item.content.length > 700) issues.push('content_too_long');
  if (looksCustomerPerspective(item.content)) issues.push('customer_perspective');
  if (hasSpecificPriceOrContact(item.content)) issues.push('specific_number_or_contact');
  const invalidPlaceholders = extractPlaceholders(item.content).filter(p => !allowedPlaceholders.has(p));
  if (invalidPlaceholders.length) issues.push('invalid_placeholder:' + invalidPlaceholders.join(','));

  const norm = normalizeText(item.content);
  if (!norm) issues.push('empty_after_normalize');
  if (seenContent.has(norm)) issues.push('duplicate_content');

  const strategyKey = item.strategy_tag.toLowerCase();
  if (strategyKey && seenStrategy.has(strategyKey)) issues.push('duplicate_strategy_tag');
  if (strategyPool.length && strategyKey && !strategyPool.includes(strategyKey)) issues.push('strategy_tag_outside_pool');

  if (issues.length) {
    rejected.push({ index: i, name: item.name, strategy_tag: item.strategy_tag, issues, preview: item.content.slice(0, 160) });
    continue;
  }

  seenContent.add(norm);
  if (strategyKey) seenStrategy.add(strategyKey);
  kept.push(item);
}

const finalTemplates = kept.slice(0, targetCount);
const shortage = Math.max(0, targetCount - finalTemplates.length);
const needsManualReview = !input.parse_ok || shortage > 0 || rejected.length > 0;
let score = 100;
if (!input.parse_ok) score -= 40;
score -= shortage * 12;
score -= Math.min(30, rejected.length * 2);
score = Math.max(0, score);

const issues = [];
if (!input.parse_ok) issues.push('parse_error:' + (input.parse_error || 'unknown'));
if (shortage > 0) issues.push('shortage:' + shortage);
if (rejected.length > 0) issues.push('rejected:' + rejected.length);

return [{
  json: {
    intent,
    category,
    targetCount,
    generationCount: input.generationCount || sourceTemplates.length,
    parsed_count: input.parsed_count || sourceTemplates.length,
    parse_ok: !!input.parse_ok,
    parse_error: input.parse_error || null,
    final_count: finalTemplates.length,
    rejected_count: rejected.length,
    shortage,
    quality_score: score,
    needs_manual_review: needsManualReview,
    issues,
    rejected,
    templates: finalTemplates
  }
}];

const items = $input.all();
const form = $('Input Gaya Bahasa').first().json;
const gaya = form['Gaya Bahasa'];
const botId = form['Bot ID'] || null;

let allTemplates = [];
let report = [];
let totalRejected = 0;
let intentsNeedingReview = 0;

for (const item of items) {
  const row = item.json || {};
  const tpls = Array.isArray(row.templates) ? row.templates : [];
  allTemplates.push(...tpls);
  totalRejected += row.rejected_count || 0;
  if (row.needs_manual_review) intentsNeedingReview++;
  report.push({
    intent: row.intent,
    category: row.category,
    target: row.targetCount,
    generated: row.generationCount,
    parsed: row.parsed_count,
    final: row.final_count,
    shortage: row.shortage,
    rejected: row.rejected_count,
    parse_ok: row.parse_ok,
    quality_score: row.quality_score,
    needs_manual_review: row.needs_manual_review,
    issues: row.issues || []
  });
}

report.sort((a, b) => String(a.intent).localeCompare(String(b.intent)));
allTemplates.sort((a, b) => String(a.sub_category || '').localeCompare(String(b.sub_category || '')) || String(a.name || '').localeCompare(String(b.name || '')));

const avgQuality = report.length ? Math.round(report.reduce((sum, r) => sum + (r.quality_score || 0), 0) / report.length) : 0;

const output = {
  meta: {
    generator: 'Template Generator V4 — Optimized (Review + JSON)',
    gaya_bahasa: gaya,
    bot_id: botId,
    total_templates: allTemplates.length,
    total_intents: report.length,
    intents_needing_manual_review: intentsNeedingReview,
    total_rejected_drafts: totalRejected,
    average_quality_score: avgQuality,
    generated_at: new Date().toISOString()
  },
  quality_report: report,
  templates: allTemplates
};

const dateStr = new Date().toISOString().slice(0, 10);
const jsonFileName = 'templates_review_ready_' + dateStr + '.json';
const mdFileName = 'templates_review_report_' + dateStr + '.md';

let md = '';
md += '# Dokumentasi Template Chatbot (Review V4)\n\n';
md += '- Generated: ' + new Date().toLocaleString() + '\n';
md += '- Gaya Bahasa: ' + gaya + '\n';
md += '- Bot ID: ' + (botId || '-') + '\n';
md += '- Total intent: ' + report.length + '\n';
md += '- Total template final: ' + allTemplates.length + '\n';
md += '- Rata-rata quality score: ' + avgQuality + '\n';
md += '- Intent perlu review manual: ' + intentsNeedingReview + '\n\n';
md += '## Ringkasan Kualitas per Intent\n\n';
md += '| Intent | Target | Final | Rejected | Score | Review | Catatan |\n';
md += '|---|---:|---:|---:|---:|---|---|\n';
for (const r of report) {
  md += '| ' + r.intent + ' | ' + r.target + ' | ' + r.final + ' | ' + r.rejected + ' | ' + r.quality_score + ' | ' + (r.needs_manual_review ? 'Ya' : 'Tidak') + ' | ' + ((r.issues || []).join(', ') || '-') + ' |\n';
}

const grouped = {};
for (const t of allTemplates) {
  if (!grouped[t.category]) grouped[t.category] = {};
  if (!grouped[t.category][t.sub_category]) grouped[t.category][t.sub_category] = [];
  grouped[t.category][t.sub_category].push(t);
}

md += '\n## Template Final (Siap Direview)\n';
for (const category of Object.keys(grouped).sort()) {
  md += '\n### ' + category + '\n';
  for (const subCategory of Object.keys(grouped[category]).sort()) {
    md += '\n#### ' + subCategory + '\n';
    grouped[category][subCategory].forEach((t, idx) => {
      md += '\n' + (idx + 1) + '. **' + (t.name || 'Unnamed') + '**';
      if (t.strategy_tag) md += ' _(strategy: ' + t.strategy_tag + ')_';
      if (t.requires_rag) md += ' [RAG]';
      md += '\n\n' + t.content + '\n';
    });
  }
}

const jsonString = JSON.stringify(output, null, 2);

return [{
  json: {
    fileName: jsonFileName,
    reviewFileName: mdFileName,
    totalTemplates: allTemplates.length,
    totalIntents: report.length,
    averageQualityScore: avgQuality,
    intentsNeedingReview: intentsNeedingReview,
    botId,
    summary: report.map(r => r.intent + ': ' + r.final + '/' + r.target + ' (score ' + r.quality_score + ')').join('\n'),
    preview: allTemplates.slice(0, 3).map(t => '[' + t.sub_category + '] ' + t.name).join(', ')
  },
  binary: {
    json_file: {
      data: Buffer.from(jsonString, 'utf-8').toString('base64'),
      mimeType: 'application/json',
      fileName: jsonFileName
    },
    review_md: {
      data: Buffer.from(md, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: mdFileName
    }
  }
}];
